// MOCK ENRICHMENT (demo mode). Production version calls Apollo organizations/enrich with the same output shape.
const d = $json.email_domain || '';
const db = {
  'northwesternmutual.com': { name: 'Northwestern Mutual', industry: 'insurance', estimated_num_employees: 7500, hq: 'Milwaukee, WI' },
  'farmers.com':            { name: 'Farmers Insurance', industry: 'insurance', estimated_num_employees: 12000, hq: 'Los Angeles, CA' },
  'regionsbank.com':        { name: 'Regions Bank', industry: 'banking', estimated_num_employees: 20000, hq: 'Birmingham, AL' },
  'ameriprise.com':         { name: 'Ameriprise Financial', industry: 'wealth management', estimated_num_employees: 14000, hq: 'Minneapolis, MN' },
  'chime.com':              { name: 'Chime', industry: 'fintech', estimated_num_employees: 1500, hq: 'San Francisco, CA' },
  'gmail.com':              { name: 'Personal Email', industry: 'unknown', estimated_num_employees: 0, hq: '' }
};
const org = db[d] || { name: d.split('.')[0], industry: 'unknown', estimated_num_employees: 200, hq: '' };
return [{ json: { ...$json, organization: org } }];

// MOCK AI SCORING (demo mode). Production version sends this exact context to Claude and gets the same JSON shape back.
const org = $json.organization || {};
const problem = ($json.problem_statement || '').toLowerCase();
let score = 0;
const reasons = [];
// Industry fit (0-3)
const icp = ['insurance', 'banking', 'wealth management', 'fintech', 'financial services'];
if (icp.includes(org.industry)) { score += 3; reasons.push('industry match: ' + org.industry); }
// Size fit (0-3)
if (org.estimated_num_employees >= 5000) { score += 3; reasons.push('enterprise scale: ' + org.estimated_num_employees + ' employees'); }
else if (org.estimated_num_employees >= 500) { score += 2; reasons.push('mid-enterprise: ' + org.estimated_num_employees + ' employees'); }
// Problem relevance (0-3)
if (/ramp|onboard|train|coach|hire|new rep|advisor|agent/.test(problem)) { score += 3; reasons.push('problem is core use case: sales ramp/training'); }
else if (/sales|revenue|quota|pipeline/.test(problem)) { score += 2; reasons.push('sales performance problem'); }
// Urgency signal (0-1)
if (/\d+/.test(problem)) { score += 1; reasons.push('quantified need stated'); }
const tier = score >= 7 ? 'T1' : 'T2';
const firstName = ($json.lead_name || '').split(' ')[0];
const reply_draft = `Hi ${firstName}, thanks for reaching out. ${org.industry === 'insurance' ? 'Insurance sales teams' : org.industry === 'banking' ? 'Banking sales teams' : 'Enterprise sales teams'} use AI roleplays to cut new hire ramp from 90 days to about 15, reps practice against AI buyers before real calls. Given what you shared about ${$json.problem_statement}, a 20 minute walkthrough would show you exactly how that works for a team your size. Grab a time here: https://cal.com/YOUR-TEAM/demo`;
return [{ json: { ...$json, score, tier, reasoning: reasons.join('; '), reply_draft } }];
